document.addEventListener('DOMContentLoaded', () => {
  const toggles = document.querySelectorAll('.app-nav__toggle');

  toggles.forEach(toggle => {
    if (toggle.tagName.toLowerCase() === 'button') {
      toggle.addEventListener('click', () => {
        const sublist = toggle.nextElementSibling;
        if (sublist) {
          sublist.classList.toggle('app-nav__sublist--show');
          toggle.classList.toggle('app-nav__toggle--active');
        }
      });
    }
  });

  const activeLink = document.querySelector('.app-nav__toggle--active[href]');
  if (activeLink) {
    let parent = activeLink.closest('.app-nav__sublist');
    while (parent) {
      parent.classList.add('app-nav__sublist--show');
      const toggleBtn = parent.previousElementSibling;
      if (toggleBtn && toggleBtn.classList.contains('app-nav__toggle')) {
        toggleBtn.classList.add('app-nav__toggle--active');
      }
      parent = parent.parentElement.closest('.app-nav__sublist');
    }
  }

  const toggleAppPageNavigation = document.getElementById('toggleAppPageNavigation');
  const appPageNavigation = document.getElementById('appPageNavigation');

  if (!toggleAppPageNavigation || !appPageNavigation) return;

  toggleAppPageNavigation.addEventListener('click', () => {
    const isExpanded =
      toggleAppPageNavigation.getAttribute('aria-expanded') === 'true';

    toggleAppPageNavigation.setAttribute('aria-expanded', String(!isExpanded));

    appPageNavigation.classList.toggle(
      'app-layout__sidebar--open',
      !isExpanded
    );
  });



});

// Escape HTML special characters
function escapeHTML(str) {
  return str
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#39;");
}

// Process each block
document.querySelectorAll(".fcdo-component").forEach(block => {
  const exampleElem = block.querySelector(".fcdo-component__example");
  const htmlCode = block.querySelector("pre.language-html > code");
  const button = block.querySelector(".copyHTML");

  if (exampleElem && htmlCode) {
    // Set code directly, Highlight.js will handle it
    htmlCode.textContent = exampleElem.innerHTML.trim();

    button.addEventListener("click", () => {
      navigator.clipboard.writeText(htmlCode.textContent).then(() => {
        button.textContent = "Code copied";
        button.disabled = true;

        setTimeout(() => {
          button.textContent = "Copy code";
          button.disabled = false;
        }, 2000);
      });
    });
  }
});

document.querySelectorAll('.fcdo-component__link').forEach(link => {
    link.addEventListener('click', function(e) {
        e.preventDefault();

        const wrapper = this.closest('.fcdo-component');
        const target = wrapper.querySelector('.fcdo-component__html');

        // toggle content
        target.classList.toggle('fcdo-component__html--open');

        // toggle link state
        this.classList.toggle('fcdo-component__link--active');
    });
});